'use client';

import { useEffect, useState, useCallback } from 'react';
import Hero from '@/components/Hero';
import QuoteDivider from '@/components/QuoteDivider';
import StatsRow from '@/components/StatsRow';
import FilterBar from '@/components/FilterBar';
import RepoGrid from '@/components/RepoGrid';
import DonutChart from '@/components/DonutChart';
import BFModal from '@/components/BFModal';
import { fuzzyFilter } from '@/lib/fuzzy';
import type { Repo, ReposData } from '@/types/repo';

const PORTFOLIO_LANGS = [
  'HTML', 'CSS', 'JavaScript', 'TypeScript', 'WebAssembly',
  'Python', 'Lua', 'SQL', 'Markdown', 'GLSL', 'SVG', 'JSON',
  'CoffeeScript', 'brainf*ck',
];

function formatAgo(iso: string): string {
  if (!iso) return '';
  const s = (Date.now() - new Date(iso).getTime()) / 1000;
  if (s < 3600) return `${Math.floor(s / 60)}m ago`;
  if (s < 86400) return `${Math.floor(s / 3600)}h ago`;
  if (s < 2592000) return `${Math.floor(s / 86400)}d ago`;
  return `${Math.floor(s / 2592000)}mo ago`;
}

export default function HomePage() {
  const [allRepos, setAllRepos] = useState<Repo[]>([]);
  const [lastUpdated, setLastUpdated] = useState('');
  const [activeLang, setActiveLang] = useState('all');
  const [sort, setSort] = useState('updatedAt');
  const [search, setSearch] = useState('');
  const [bfOpen, setBfOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    fetch('/repos.json')
      .then((r) => r.json())
      .then((data: ReposData) => {
        setAllRepos(data.repos ?? []);
        setLastUpdated(data.lastUpdated ?? '');
        setLoading(false);
      })
      .catch(() => {
        setError(true);
        setLoading(false);
      });
  }, []);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (e.ctrlKey && e.key === 'b') {
      e.preventDefault();
      setBfOpen(true);
    }
  }, []);

  useEffect(() => {
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  const languages = [
    ...new Set(allRepos.map((r) => r.language).filter(Boolean) as string[]),
  ].sort();

  let filtered = activeLang === 'all'
    ? allRepos
    : allRepos.filter((r) => r.language === activeLang);

  if (search.trim()) {
    filtered = fuzzyFilter(filtered, search);
  } else {
    filtered = [...filtered].sort((a, b) => {
      if (sort === 'name') return a.name.localeCompare(b.name);
      if (sort === 'stars') return (b.stars || 0) - (a.stars || 0);
      return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
    });
  }

  return (
    <>
      <Hero />
      <QuoteDivider />

      <div className="page">
        {loading ? (
          <div className="grid-empty">Loading repositories…</div>
        ) : error ? (
          <div className="grid-empty">
            Could not load repos.json — make sure it exists in the public directory.
          </div>
        ) : (
          <>
            <StatsRow repos={allRepos} lastUpdated={lastUpdated} />

            <FilterBar
              languages={languages}
              activeLang={activeLang}
              sort={sort}
              search={search}
              onLangChange={setActiveLang}
              onSortChange={setSort}
              onSearchChange={setSearch}
            />

            <RepoGrid repos={filtered} />

            <DonutChart repos={allRepos} />
          </>
        )}
      </div>

      <footer>
        <p>
          Built with{' '}
          <strong style={{ color: 'var(--text)' }}>13 programming languages</strong>
          {lastUpdated && (
            <>
              {' '}&mdash; last synced{' '}
              <span id="last-synced">{formatAgo(lastUpdated)}</span>
            </>
          )}
        </p>
        <div className="lang-pills-row">
          {PORTFOLIO_LANGS.map((l) => (
            <span key={l} className="footer-pill">
              {l}
            </span>
          ))}
        </div>
        <p style={{ marginTop: '1rem', fontSize: '0.75rem' }}>
          Press{' '}
          <kbd
            style={{
              background: 'var(--surface)',
              border: '1px solid var(--border)',
              borderRadius: '4px',
              padding: '0.1rem 0.4rem',
            }}
          >
            Ctrl+B
          </kbd>{' '}
          for a surprise
        </p>
      </footer>

      <BFModal open={bfOpen} onClose={() => setBfOpen(false)} />
    </>
  );
}
